import React, { useState, useEffect } from "react";
import { useParams, useLocation, Link } from "react-router-dom";

import Header from "../components/common/Header";
import Navbar from "../components/common/Navbar";
import Footer from "../components/common/Footer";
import ProductCard from "../components/product/ProductCard";
import { productAPI, categoryAPI } from "../api";

const ProductList = () => {
  const { slug } = useParams();
  const location = useLocation();
  const queryParams = new URLSearchParams(location.search);

  const searchQuery = queryParams.get("q");
  const categoryQuery = queryParams.get("category");
  const [sortOption, setSortOption] = useState("alpha-asc");

  const [products, setProducts] = useState([]);
  const [categoryName, setCategoryName] = useState("");
  const [category, setCategory] = useState(null);

  const [sortOrder, setSortOrder] = useState("default");
  const [currentPage, setCurrentPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [totalProducts, setTotalProducts] = useState(0);

  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  // Khi slug / search / category thay đổi → reset về trang 1
  useEffect(() => {
    setCurrentPage(1);
  }, [slug, searchQuery, categoryQuery]);

  // Fetch sản phẩm khi các tham số thay đổi
  useEffect(() => {
    fetchProducts();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [slug, searchQuery, categoryQuery, currentPage]);

  // =============================
  //  HÀM LẤY SẢN PHẨM
  // =============================
  const fetchProducts = async () => {
    try {
      setLoading(true);
      setError("");

      let response;

      // 1️⃣ Trường hợp có search hoặc lọc category qua query
      if (searchQuery || categoryQuery) {
        // Tìm kiếm với từ khóa và/hoặc danh mục
        console.log(`Calling search API with keyword: ${searchQuery}, category: ${categoryQuery}`);
        
        response = await productAPI.searchProducts({
          keyword: searchQuery || "",
          category: categoryQuery || "all",
          page: currentPage,
        });

        if (response.data) {
          const productsData = response.data.products || [];
          setProducts(productsData);
          setTotalPages(response.data.pages || 1);
          setTotalProducts(
            response.data.total ||
              response.data.count ||
              productsData.length
          );

          let displayName = "Kết quả tìm kiếm";

          if (searchQuery && categoryQuery && categoryQuery !== "all") {
            displayName = `Tìm "${searchQuery}" trong danh mục "${categoryQuery}"`;
          } else if (searchQuery) {
            displayName = `Kết quả cho "${searchQuery}"`;
          } else if (categoryQuery && categoryQuery !== "all") {
            displayName = `Danh mục: ${categoryQuery}`;
          } else {
            displayName = "Tất cả sản phẩm";
          }

          setCategoryName(displayName);
          setCategory(null);
        }
      }
      // 2️⃣ Trường hợp có slug category trên URL: /category/:slug
      else if (slug) {
        response = await categoryAPI.getProductsByCategory(slug, currentPage);

        if (response.data) {
          const productsData = response.data.products || [];
          setProducts(productsData);
          setCategory(response.data.category || null);
          setCategoryName(
            response.data.category?.name || "Danh mục sản phẩm"
          );
          setTotalPages(response.data.pages || 1);
          setTotalProducts(
            response.data.total ||
              response.data.count ||
              productsData.length
          );
        }
      }
      // 3️⃣ Mặc định: lấy tất cả sản phẩm
      else {
        response = await productAPI.getProducts("", currentPage);

        if (response.data) {
          const productsData = response.data.products || [];
          setProducts(productsData);
          setCategory(null);
          setCategoryName("Tất cả sản phẩm");
          setTotalPages(response.data.pages || 1);
          setTotalProducts(
            response.data.total ||
              response.data.count ||
              productsData.length
          );
        }
      }

      setLoading(false);
    } catch (err) {
      console.error("❌ Lỗi tải sản phẩm:", err);
      let errorMessage = "Không thể tải sản phẩm. Vui lòng thử lại sau.";

      if (err.response) {
        errorMessage =
          err.response.data?.message ||
          `Lỗi ${err.response.status}: Không thể tải sản phẩm.`;
      } else if (err.request) {
        errorMessage =
          "Không thể kết nối đến server. Vui lòng kiểm tra kết nối mạng.";
      } else {
        errorMessage = err.message;
      }

      setError(errorMessage);
      setLoading(false);
    }
  };

  // =============================
  //  SẮP XẾP SẢN PHẨM
  // =============================
  const sortedProducts = [...products].sort((a, b) => {
    switch (sortOrder) {
      case "price-asc": {
        const priceA = a.discountPrice || a.price || 0;
        const priceB = b.discountPrice || b.price || 0;
        return priceA - priceB;
      }
      case "price-desc": {
        const priceA2 = a.discountPrice || a.price || 0;
        const priceB2 = b.discountPrice || b.price || 0;
        return priceB2 - priceA2;
      }
      case "name-asc":
        return (a.name || "").localeCompare(b.name || "", "vi");
      case "name-desc":
        return (b.name || "").localeCompare(a.name || "", "vi");
      case "newest":
        return new Date(b.createdAt || 0) - new Date(a.createdAt || 0);
      default:
        return 0;
    }
  });

  // =============================
  //  UI: LOADING / ERROR
  // =============================
  if (loading) {
    return (
  <div className="max-w-7xl mx-auto px-6 py-8">

    {/* Breadcrumb */}
    <nav className="text-sm text-gray-500 mb-4">
      <a href="/" className="hover:text-[#e06c7f]">Trang chủ</a>
      <span className="mx-1">›</span>
      <span className="text-gray-700">Sản phẩm</span>
    </nav>

    {/* Title */}
    <h1 className="text-2xl font-bold text-[#2c2c2c] mb-2">
      Tất cả sản phẩm
    </h1>

    {/* Top Bar: Summary + Filter/Sort */}
    <div className="
      bg-white shadow-sm border border-pink-100 
      rounded-xl px-4 py-3 mb-6 flex flex-col md:flex-row 
      items-start md:items-center justify-between gap-4
    ">
      {/* Left: Summary */}
      <p className="text-gray-600 text-sm">
        Đang hiển thị <b>{products.length}</b> / {totalProducts} sản phẩm
      </p>

      {/* Right: Sorting */}
      <div className="flex items-center gap-3 w-full md:w-auto">
        <span className="text-sm text-gray-600 whitespace-nowrap">
          Sắp xếp theo:
        </span>

        <select
          value={sortOption}
          onChange={(e) => setSortOption(e.target.value)}
          className="
            border border-pink-300 focus:ring-[#e06c7f]
            rounded-lg px-3 py-2 text-sm outline-none
            cursor-pointer bg-white
          "
        >
          <option value="alpha-asc">Tên: A → Z</option>
          <option value="alpha-desc">Tên: Z → A</option>
          <option value="price-asc">Giá: thấp → cao</option>
          <option value="price-desc">Giá: cao → thấp</option>
          <option value="newest">Mới nhất</option>
        </select>
      </div>
    </div>

    {/* Product Grid */}
    {loading ? (
      <p className="text-center py-8 text-gray-500">Đang tải sản phẩm...</p>
    ) : products.length === 0 ? (
      <p className="text-center py-8 text-gray-500">
        Không tìm thấy sản phẩm nào.
      </p>
    ) : (
      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6">
        {products.map((product) => (
          <ProductCard key={product._id} product={product} />
        ))}
      </div>
    )}

    {/* Pagination */}
    {totalPages > 1 && (
      <div className="flex justify-center mt-10">
        <div className="flex gap-2">
          {[...Array(totalPages)].map((_, index) => (
            <button
              key={index}
              onClick={() => setCurrentPage(index + 1)}
              className={`
                px-4 py-2 rounded-lg border 
                ${
                  currentPage === index + 1
                    ? "bg-[#e06c7f] border-[#e06c7f] text-white"
                    : "bg-white border-gray-300 text-gray-700 hover:border-[#e06c7f]"
                }
              `}
            >
              {index + 1}
            </button>
          ))}
        </div>
      </div>
    )}
  </div>
);
  }
};

export default ProductList;
